/**
 * sagittal-Key.js
 * 1:1 conversion of the "Key" sheet from
 * "Sagittal Standard JI Notation Calculator Spreadsheet - C.xlsx"
 *
 * Maps each sagittal key integer to four notation forms.
 * Keys are stored as quoted strings to support negative values.
 *
 * Column mapping in original sheet:
 *   A = key integer
 *   B = evo_ascii   – Evo  ASCII representation
 *   C = revo_ascii  – Revo ASCII representation
 *   D = evo_unicode – Evo  Unicode (Sagittal font private-use codepoints)
 *   E = revo_unicode– Revo Unicode
 */

